SELECT [CFG Variant].*
FROM [CFG Variant]
WHERE ((([CFG Variant].[Model Item No_])="7FARIA01/LEA" Or ([CFG Variant].[Model Item No_])="7FWOSUONO01/LEA" Or ([CFG Variant].[Model Item No_])="YLE14/TEXTURED" Or ([CFG Variant].[Model Item No_])="DLY32/NET" Or ([CFG Variant].[Model Item No_])="JNE04/CROSTA-VIT" Or ([CFG Variant].[Model Item No_])="7FMURRAY01/LEA" Or ([CFG Variant].[Model Item No_])="7SWOBOWLING/LEA" Or ([CFG Variant].[Model Item No_])="8SMADISON01/MES" Or ([CFG Variant].[Model Item No_])="8SMASTER01/LEA"));

